var numTrees = function(n) {
    const dp = new Array(n + 1).fill(0);
    dp[0] = 1;
    for (let nodes = 1; nodes <= n; nodes++) {
        for (let root = 0; root < nodes; root++) {
            dp[nodes] += dp[root] * dp[nodes - 1 - root];
        }
    }
    return dp[n];
};
